import { useState, useEffect } from "react";
import { Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, BarElement, Tooltip, Legend);

/**
 * ParameterComparison — Displays experiment results comparing different
 * HE parameter configurations (security level & activation degree).
 *
 * Activation-degree data is loaded dynamically from /benchmark_data.json
 * (generated by scripts/csv_to_json.py), so it auto-updates when
 * re-running the benchmark with more images.
 *
 * Security-level data remains hardcoded because 192-bit / 256-bit
 * experiments failed with OOM — there is no CSV data for them.
 */

/* ── Float-model accuracy (plaintext PyTorch) per degree ── */
const FLOAT_ACCURACY = { 2: "88.86%", 3: "87.26%", 4: "86.91%" };

/* ── Notes per degree ── */
const DEGREE_NOTES = {
  2: "Best accuracy — polynomial x² matches training activation",
  3: "Signal corruption from modular clamping in poly_activate",
  4: "Complete signal loss — higher-degree terms overflow modulus",
};

/* ── Convert a benchmark_data.json config → activation row ── */
function configToActivationRow(cfg) {
  const la = cfg.layer_averages || {};
  return {
    parameter: "Activation",
    value: cfg.label,
    accuracy: cfg.accuracy,
    accuracyPct: cfg.accuracy_pct,
    avgInferenceMs: cfg.avg_total_ms,
    encMs: la.encryption_ms ?? 0,
    conv1Ms: la.conv1_ms ?? 0,
    act1Ms: la.act1_ms ?? 0,
    pool1Ms: la.pool1_ms ?? 0,
    conv2Ms: la.conv2_ms ?? 0,
    act2Ms: la.act2_ms ?? 0,
    pool2Ms: la.pool2_ms ?? 0,
    fcMs: la.fc_ms ?? 0,
    decMs: la.decryption_ms ?? 0,
    security: cfg.security || "128-bit",
    notes: DEGREE_NOTES[cfg.degree] || "",
    floatAccuracy: FLOAT_ACCURACY[cfg.degree] || "—",
    numImages: cfg.num_images,
  };
}

/* ── Security-level data (hardcoded — OOM means no CSV) ── */
const SECURITY_ROWS = [
  {
    parameter: "Security",
    value: "128-bit",
    accuracy: null, // filled dynamically from deg-2 config
    accuracyPct: null,
    avgInferenceMs: null,
    keygenNote: "< 5s",
    memoryNote: "~2.5 GB",
    security: "128-bit",
    notes: "Standard NIST security level — works on t3.xlarge",
  },
  {
    parameter: "Security",
    value: "192-bit",
    accuracy: "—",
    accuracyPct: null,
    avgInferenceMs: null,
    keygenNote: "> 60 min (OOM)",
    memoryNote: "> 7.6 GB",
    security: "192-bit",
    notes: "BFV context creation failed — requires larger ring dimension, exceeded 7.6 GB RAM + 15 GB swap",
  },
  {
    parameter: "Security",
    value: "256-bit",
    accuracy: "—",
    accuracyPct: null,
    avgInferenceMs: null,
    keygenNote: "N/A",
    memoryNote: "> 7.6 GB",
    security: "256-bit",
    notes: "Not attempted — 192-bit already infeasible on t3.xlarge",
  },
];

/* ── Colour helpers ── */
const accuracyColor = (pct) => {
  if (pct === null) return "#999";
  if (pct >= 80) return "#0aa35e";
  if (pct >= 40) return "#e68a00";
  return "#e03e52";
};

const formatMs = (ms) => {
  if (ms === null || ms === undefined) return "—";
  if (ms >= 1000) return `${(ms / 1000).toFixed(1)}s`;
  return `${ms.toFixed(0)}ms`;
};

/* ── Convert a scale/modulus JSON config → row ── */
function configToExperimentRow(cfg, parameter) {
  const la = cfg.layer_averages || {};
  return {
    parameter,
    value: cfg.label,
    accuracy: cfg.accuracy,
    accuracyPct: cfg.accuracy_pct,
    avgInferenceMs: cfg.avg_total_ms,
    encMs: la.encryption_ms ?? 0,
    conv1Ms: la.conv1_ms ?? 0,
    act1Ms: la.act1_ms ?? 0,
    pool1Ms: la.pool1_ms ?? 0,
    conv2Ms: la.conv2_ms ?? 0,
    act2Ms: la.act2_ms ?? 0,
    pool2Ms: la.pool2_ms ?? 0,
    fcMs: la.fc_ms ?? 0,
    decMs: la.decryption_ms ?? 0,
    security: cfg.security || "128-bit",
    numImages: cfg.num_images,
    notes: "",
  };
}

/* ── Main Component ── */
export default function ParameterComparison() {
  const [activeTab, setActiveTab] = useState("activation"); // "activation" | "security" | "scale" | "modulus"
  const [activationRows, setActivationRows] = useState([]);
  const [scaleRows, setScaleRows] = useState([]);
  const [modulusRows, setModulusRows] = useState([]);
  const [numImages, setNumImages] = useState(0);
  const [scaleNumImages, setScaleNumImages] = useState(0);
  const [modulusNumImages, setModulusNumImages] = useState(0);
  const [loading, setLoading] = useState(true);

  /* Load all JSON data on mount */
  useEffect(() => {
    const loadAll = async () => {
      // Load activation degree data
      try {
        const res = await fetch("/benchmark_data.json");
        if (res.ok) {
          const data = await res.json();
          const rows = (data.configs || []).map(configToActivationRow);
          setActivationRows(rows);
          const n = data.configs?.[0]?.num_images || data.total_images || 0;
          setNumImages(n);
          const deg2 = data.configs?.find((c) => c.degree === 2);
          if (deg2) {
            SECURITY_ROWS[0].accuracy = deg2.accuracy;
            SECURITY_ROWS[0].accuracyPct = deg2.accuracy_pct;
            SECURITY_ROWS[0].avgInferenceMs = deg2.avg_total_ms;
          }
        }
      } catch (e) { /* ignore */ }

      // Load scale factor data
      try {
        const res = await fetch("/scale_factor_data.json");
        if (res.ok) {
          const data = await res.json();
          const rows = (data.configs || []).map((c) => configToExperimentRow(c, "Scale Factor"));
          setScaleRows(rows);
          setScaleNumImages(data.total_images || 0);
        }
      } catch (e) { /* ignore */ }

      // Load plaintext modulus data
      try {
        const res = await fetch("/plaintext_modulus_data.json");
        if (res.ok) {
          const data = await res.json();
          const rows = (data.configs || []).map((c) => configToExperimentRow(c, "Plaintext Modulus"));
          setModulusRows(rows);
          setModulusNumImages(data.total_images || 0);
        }
      } catch (e) { /* ignore */ }

      setLoading(false);
    };
    loadAll();
  }, []);

  const rows =
    activeTab === "activation" ? activationRows :
    activeTab === "security" ? SECURITY_ROWS :
    activeTab === "scale" ? scaleRows :
    modulusRows;

  const showLayerChart = activeTab === "activation" || activeTab === "scale" || activeTab === "modulus";
  const chartRows =
    activeTab === "scale" ? scaleRows :
    activeTab === "modulus" ? modulusRows :
    activationRows;

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-purple-600" />
        <span className="ml-2 text-xs text-gray-500">Loading experiment data…</span>
      </div>
    );
  }

  return (
    <div>
      {/* Tab selector */}
      <div className="flex flex-wrap gap-2 mb-5">
        {[
          { id: "activation", label: "Activation Degree", desc: "x² vs degree 3 vs degree 4" },
          { id: "security", label: "Security Level", desc: "128-bit vs 192-bit vs 256-bit" },
          { id: "scale", label: "Scale Factor", desc: "S=100 vs S=1,000 vs S=10,000", hidden: scaleRows.length === 0 },
          { id: "modulus", label: "Plaintext Modulus", desc: "16-bit vs baseline vs 32-bit", hidden: modulusRows.length === 0 },
        ].filter((t) => !t.hidden).map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`px-4 py-2.5 rounded-lg text-sm font-medium transition-all ${
              activeTab === tab.id
                ? "bg-[#1a1a2e] text-white shadow-md"
                : "bg-white text-gray-600 border border-gray-200 hover:border-gray-300 hover:bg-gray-50"
            }`}
          >
            {tab.label}
            <span className="block text-[10px] font-normal mt-0.5 opacity-70">{tab.desc}</span>
          </button>
        ))}
      </div>

      {/* Results table */}
      <div className="overflow-x-auto rounded-lg border border-gray-200">
        <table className="w-full text-sm">
          <thead>
            <tr style={{ background: "#f8f8f8" }}>
              <th className="text-left px-4 py-3 font-medium text-xs uppercase tracking-wider" style={{ color: "#888" }}>
                Configuration
              </th>
              <th className="text-center px-4 py-3 font-medium text-xs uppercase tracking-wider" style={{ color: "#888" }}>
                Accuracy
              </th>
              <th className="text-center px-4 py-3 font-medium text-xs uppercase tracking-wider" style={{ color: "#888" }}>
                Avg Inference
              </th>
              {activeTab === "activation" && (
                <th className="text-center px-4 py-3 font-medium text-xs uppercase tracking-wider" style={{ color: "#888" }}>
                  Float Accuracy
                </th>
              )}
              {activeTab === "security" && (
                <>
                  <th className="text-center px-4 py-3 font-medium text-xs uppercase tracking-wider" style={{ color: "#888" }}>
                    Keygen
                  </th>
                  <th className="text-center px-4 py-3 font-medium text-xs uppercase tracking-wider" style={{ color: "#888" }}>
                    Memory
                  </th>
                </>
              )}
              <th className="text-left px-4 py-3 font-medium text-xs uppercase tracking-wider" style={{ color: "#888" }}>
                Notes
              </th>
            </tr>
          </thead>
          <tbody>
            {rows.map((row, i) => (
              <tr
                key={i}
                className="border-t transition-colors hover:bg-gray-50"
                style={{ borderColor: "#eee" }}
              >
                {/* Configuration */}
                <td className="px-4 py-3">
                  <div className="font-medium" style={{ color: "#333" }}>{row.value}</div>
                  <div className="text-[11px]" style={{ color: "#aaa" }}>{row.security}</div>
                </td>

                {/* Accuracy */}
                <td className="text-center px-4 py-3">
                  <span
                    className="inline-block px-2.5 py-1 rounded-full text-xs font-bold"
                    style={{
                      color: accuracyColor(row.accuracyPct),
                      background: row.accuracyPct === null ? "#f5f5f5" : `${accuracyColor(row.accuracyPct)}15`,
                    }}
                  >
                    {row.accuracy}
                  </span>
                </td>

                {/* Avg Inference */}
                <td className="text-center px-4 py-3 font-mono text-sm" style={{ color: row.avgInferenceMs ? "#333" : "#999" }}>
                  {row.avgInferenceMs ? formatMs(row.avgInferenceMs) : "—"}
                </td>

                {/* Conditional columns */}
                {activeTab === "activation" && (
                  <td className="text-center px-4 py-3 text-xs" style={{ color: "#666" }}>
                    {row.floatAccuracy || "—"}
                  </td>
                )}
                {activeTab === "security" && (
                  <>
                    <td className="text-center px-4 py-3 text-xs font-mono" style={{ color: row.keygenNote?.includes("OOM") ? "#e03e52" : "#666" }}>
                      {row.keygenNote || "—"}
                    </td>
                    <td className="text-center px-4 py-3 text-xs font-mono" style={{ color: "#666" }}>
                      {row.memoryNote || "—"}
                    </td>
                  </>
                )}

                {/* Notes */}
                <td className="px-4 py-3 text-xs max-w-[300px]" style={{ color: "#888" }}>
                  {row.notes}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Per-layer breakdown chart (activation, scale, modulus tabs) */}
      {showLayerChart && chartRows.length > 0 && (
        <div className="mt-6">
          <h4 className="text-xs font-medium uppercase tracking-wider mb-3" style={{ color: "#888" }}>
            Per-Layer Timing Breakdown (ms)
          </h4>
          <div className="rounded-lg p-4" style={{ background: "#fff", border: "1px solid #e5e5e5" }}>
            <div style={{ height: 260 }}>
              <Bar
                data={{
                  labels: chartRows.map((r) => r.value),
                  datasets: [
                    { label: "Encrypt", data: chartRows.map((r) => r.encMs), backgroundColor: "#0db7c4" },
                    { label: "Conv1", data: chartRows.map((r) => r.conv1Ms), backgroundColor: "#7b3ff2" },
                    { label: "Act1", data: chartRows.map((r) => r.act1Ms), backgroundColor: "#e68a00" },
                    { label: "Pool1", data: chartRows.map((r) => r.pool1Ms), backgroundColor: "#f4b942" },
                    { label: "Conv2", data: chartRows.map((r) => r.conv2Ms), backgroundColor: "#9b6dff" },
                    { label: "Act2", data: chartRows.map((r) => r.act2Ms), backgroundColor: "#ff9f43" },
                    { label: "Pool2", data: chartRows.map((r) => r.pool2Ms), backgroundColor: "#ffc857" },
                    { label: "FC", data: chartRows.map((r) => r.fcMs), backgroundColor: "#e03e52" },
                    { label: "Decrypt", data: chartRows.map((r) => r.decMs), backgroundColor: "#0aa35e" },
                  ],
                }}
                options={{
                  responsive: true,
                  maintainAspectRatio: false,
                  plugins: {
                    legend: {
                      position: "bottom",
                      labels: { boxWidth: 12, padding: 10, font: { size: 10 } },
                    },
                    tooltip: {
                      callbacks: {
                        label: (ctx) => `${ctx.dataset.label}: ${ctx.raw.toFixed(0)}ms`,
                      },
                    },
                  },
                  scales: {
                    x: { stacked: true, grid: { display: false } },
                    y: {
                      stacked: true,
                      title: { display: true, text: "Time (ms)", font: { size: 11 } },
                      grid: { color: "#f0f0f0" },
                    },
                  },
                }}
              />
            </div>
          </div>
        </div>
      )}

      {/* Key findings callout */}
      <div className="mt-5 rounded-lg p-4" style={{ background: "#fffbe6", border: "1px solid #ffe58f" }}>
        <p className="text-xs font-medium mb-1.5" style={{ color: "#ad6800" }}>
          Key Findings
        </p>
        {activeTab === "activation" ? (
          <ul className="text-xs space-y-1" style={{ color: "#8c6200" }}>
            <li>• <b>x² (degree 2)</b> achieves {activationRows[0]?.accuracyPct ?? "—"}% FHE accuracy ({activationRows[0]?.accuracy}) — matching the activation used during training gives best results. Validated.</li>
            <li>• <b>Degree 3</b> drops to {activationRows[1]?.accuracyPct ?? "—"}% — the cubic term amplifies intermediate values beyond the plaintext modulus (100,073,473), causing modular wrap-around that corrupts activations. Noise overflow.</li>
            <li>• <b>Degree 4</b> drops to {activationRows[2]?.accuracyPct ?? "—"}% — even the degree-3 failure mode is compounded by a fourth-power term; the signal is completely destroyed before FC. Run incomplete.</li>
            <li>• Inference time is similar across degrees (~12–14s) — the bottleneck is Conv/FC ciphertext multiply, not activation. This confirms activation degree is an accuracy knob, not a latency knob.</li>
          </ul>
        ) : activeTab === "scale" ? (
          <ul className="text-xs space-y-1" style={{ color: "#8c6200" }}>
            <li>• <b>S = 100</b> — Low precision: more quantization error, but faster computation. Accuracy: {scaleRows[0]?.accuracyPct ?? "—"}%.</li>
            <li>• <b>S = 1,000</b> — Baseline precision used during training. Accuracy: {scaleRows[1]?.accuracyPct ?? "—"}%.</li>
            <li>• <b>S = 10,000</b> — High precision: less quantization error, but larger ciphertexts. Accuracy: {scaleRows[2]?.accuracyPct ?? "—"}%.</li>
            <li>• Higher scale factors reduce rounding errors but increase the risk of plaintext modulus overflow.</li>
          </ul>
        ) : activeTab === "modulus" ? (
          <ul className="text-xs space-y-1" style={{ color: "#8c6200" }}>
            <li>• <b>p = 65,537</b> — Small 16-bit modulus: high overflow risk, accuracy {modulusRows[0]?.accuracyPct ?? "—"}%.</li>
            <li>• <b>p = 100,073,473</b> — Baseline: sufficient headroom for scale=1000. Accuracy: {modulusRows[1]?.accuracyPct ?? "—"}%.</li>
            <li>• <b>p = 4,294,967,311</b> — Large 32-bit modulus: more headroom but slower operations. Accuracy: {modulusRows[2]?.accuracyPct ?? "—"}%.</li>
            <li>• The plaintext modulus must be large enough to hold all intermediate computation values without wrapping around.</li>
          </ul>
        ) : (
          <ul className="text-xs space-y-1" style={{ color: "#8c6200" }}>
            <li>• <b>128-bit</b> security works on r6i.large (~2.5 GB RAM); BFV keygen completes in under 5 seconds. Validated.</li>
            <li>• <b>192-bit</b> requires a larger ring dimension (n ≥ 8192), causing BFV context creation to exhaust 7.6 GB RAM + 15 GB swap — keygen never completed after 60+ minutes. OOM failure.</li>
            <li>• <b>256-bit</b> would need n ≥ 16384 — memory requirements exceed single-instance feasibility entirely. Not attempted.</li>
            <li>• <b>Design decision:</b> 128-bit is the hardware ceiling for a single-node commodity cloud deployment. Higher levels require a distributed key-management architecture (future work).</li>
          </ul>
        )}
      </div>

      {/* Experiment metadata */}
      <div className="mt-3 text-[10px] flex flex-wrap gap-x-4 gap-y-1" style={{ color: "#bbb" }}>
        <span>EC2: t3.xlarge (4 vCPU, 7.6 GB RAM)</span>
        <span>OpenFHE v1.2.2 (BFV)</span>
        {activeTab === "scale" ? (
          <span>p = 100,073,473 · degree = 2</span>
        ) : activeTab === "modulus" ? (
          <span>scale = 1,000 · degree = 2</span>
        ) : (
          <>
            <span>p = 100,073,473</span>
            <span>mult_depth = 6</span>
            <span>scale = 1000</span>
          </>
        )}
        <span>
          {activeTab === "scale" ? scaleNumImages :
           activeTab === "modulus" ? modulusNumImages :
           numImages} MNIST test images per config
        </span>
      </div>
    </div>
  );
}
